```go
import "sort"

func solve(n int64, edges [][]int64, k int64) int64 {
    sort.Slice(edges, func(i, j int) bool {
        return edges[i][2] < edges[j][2]
    })
    if len(edges) == 0 {
        return 0
    }
    maxTime := 0
    for _, e := range edges {
        if e[2] > maxTime {
            maxTime = e[2]
        }
    }
    low := 0
    high := maxTime
    answer := maxTime

    func is_valid(t int64) bool {
        parent := make([]int64, int(n))
        for i := 0; i < int(n); i++ {
            parent[i] = int64(i)
        }
        rank := make([]int64, int(n))
        var find func(u int64) int64
        find = func(u int64) int64 {
            if parent[u] != u {
                parent[u] = find(parent[u])
            }
            return parent[u]
        }
        for _, edge := range edges {
            u := edge[0]
            v := edge[1]
            timeEdge := edge[2]
            if timeEdge > t {
                rootU := find(u)
                rootV := find(v)
                if rootU != rootV {
                    if rank[rootU] > rank[rootV] {
                        parent[rootV] = rootU
                    } else {
                        parent[rootU] = rootV
                        if rank[rootU] == rank[rootV] {
                            rank[rootV]++
                        }
                    }
                }
            }
        }
        roots := make(map[int64]bool)
        for i := 0; i < int(n); i++ {
            roots[find(int64(i))] = true
        }
        return len(roots) >= int(k)
    }

    for low <= high {
        mid := (low + high) / 2
        if is_valid(mid) {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    return answer
}
