package main

import (
	"sort"
)

func find(parent []int64, x int64) int64 {
	if parent[x] != x {
		parent[x] = find(parent, parent[x])
	}
	return parent[x]
}

func solve(n int64, edges [][]int64, k int64) int64 {
	if len(edges) == 0 {
		return 0
	}
	sort.Slice(edges, func(i, j int) bool {
		return edges[i][2] < edges[j][2]
	})
	maxTime := edges[len(edges)-1][2]
	low, high := 0, int64(maxTime)
	answer := int64(maxTime)

	for low <= high {
		mid := (low + high) / 2
		if is_valid(mid, n, edges, k) {
			answer = mid
			high = mid - 1
		} else {
			low = mid + 1
		}
	}
	return answer
}

func is_valid(t int64, n int64, edges [][]int64, k int64) bool {
	parent := make([]int64, n)
	rank := make([]int64, n)
	for i := int64(0); i < n; i++ {
		parent[i] = i
		rank[i] = 1
	}
	for _, edge := range edges {
		u, v, time := edge[0], edge[1], edge[2]
		if time > t {
			x := find(parent, u)
			y := find(parent, v)
			if x != y {
				if rank[x] < rank[y] {
					parent[x] = y
				} else {
					parent[y] = x
					if rank[x] == rank[y] {
						rank[x]++
					}
				}
			}
		}
	}
	roots := make(map[int64]bool)
	for i := 0; i < int(n); i++ {
		roots[find(parent, int64(i))] = true
	}
	return len(roots) >= int(k)
}
